16	//
17	// RBTDRL — calibrant fixtures: synthetic test inputs with deterministic
18	// verdicts that exercise the operator-facing surface of the theurge engine.
19	// Internal framework-test plumbing; not end-user-facing.
20	//
21	// Four fixtures registered through rbtdrm_manifest.rs and dispatched via
22	// rbtdrc_crucible.rs:
23	//
24	//   calibrant-verdicts      Independent       4 cases   verdict-path coverage
25	//   calibrant-fail-fast     Independent       4 cases   intra/inter-section fail-fast
26	//   calibrant-progressing   StateProgressing  2 cases   probe Ok/Err dispatch
27	//   calibrant-sentinel      Independent       1 case    suite-fail-fast pivot
28	//
29	// All four declare empty rbtdrm_required_colophons — calibrant cases never
30	// shell out to bash tabtargets, so the manifest-coupling check is vacuous.
31	//
32	// A bash blackbox testbench consumes these fixtures and asserts engine-output
33	// contracts (exit codes, stderr format, fail-fast semantics, disposition ×
34	// keep-going policy gate).
35	
36	use std::path::Path;
37	
38	use crate::case;
39	use crate::rbtdrb_probe::{rbtdrb_assert, rbtdrb_Probe};
40	use crate::rbtdre_engine::{rbtdre_Disposition, rbtdre_Fixture, rbtdre_Section, rbtdre_Verdict};
41	use crate::rbtdrm_manifest::{
42	    RBTDRM_FIXTURE_CALIBRANT_FAIL_FAST, RBTDRM_FIXTURE_CALIBRANT_PROGRESSING,
43	    RBTDRM_FIXTURE_CALIBRANT_SENTINEL, RBTDRM_FIXTURE_CALIBRANT_VERDICTS,
44	};
45	
46	/// Sentinel filename written into a case's temp dir to mark execution. The
47	/// blackbox driver asserts presence/absence by globbing under the
48	/// BURV_TEMP_ROOT_DIR it set for the rbtd invocation. I/O failure during
49	/// sentinel write fails the case visibly — silent failure would hide bugs in
50	/// the engine's case-dir contract.
51	pub(crate) const RBTDRL_SENTINEL_FILE: &str = "ran.sentinel";
52	
53	/// Case-written output filename. Distinct from the engine's auto-written
54	/// trace.txt so the blackbox driver can verify both the engine's per-case
55	/// trace contract and the case's own write contract.
56	pub(crate) const RBTDRL_OUTPUT_FILE: &str = "output.txt";
57	
58	fn rbtdrl_write_sentinel(dir: &Path) -> Result<(), rbtdre_Verdict> {
59	    std::fs::write(dir.join(RBTDRL_SENTINEL_FILE), "")
60	        .map_err(|e| rbtdre_Verdict::Fail(format!("sentinel write failed: {}", e)))
61	}
62	
63	// ── calibrant-verdicts ──────────────────────────────────────
64	
65	fn rbtdrl_verdicts_pass(_dir: &Path) -> rbtdre_Verdict {
66	    rbtdre_Verdict::Pass
67	}
68	
69	fn rbtdrl_verdicts_fail(_dir: &Path) -> rbtdre_Verdict {
70	    rbtdre_Verdict::Fail("calibrant deterministic fail verdict".to_string())
71	}
72	
73	fn rbtdrl_verdicts_skip(_dir: &Path) -> rbtdre_Verdict {
74	    rbtdre_Verdict::Skip("calibrant deterministic skip verdict".to_string())
75	}
76	
77	fn rbtdrl_verdicts_pass_with_output(dir: &Path) -> rbtdre_Verdict {
78	    if let Err(e) = std::fs::write(
79	        dir.join(RBTDRL_OUTPUT_FILE),
80	        "calibrant case-written output\n",
81	    ) {
82	        return rbtdre_Verdict::Fail(format!("output write failed: {}", e));
83	    }
84	    rbtdre_Verdict::Pass
85	}
86	
87	pub static RBTDRL_SECTIONS_VERDICTS: &[rbtdre_Section] = &[rbtdre_Section {
88	    name: "calibrant-verdicts",
89	    cases: &[
90	        case!(rbtdrl_verdicts_pass),
91	        case!(rbtdrl_verdicts_fail),
92	        case!(rbtdrl_verdicts_skip),
93	        case!(rbtdrl_verdicts_pass_with_output),
94	    ],
95	}];
96	
97	// ── calibrant-fail-fast ─────────────────────────────────────
98	
99	fn rbtdrl_failfast_pass(_dir: &Path) -> rbtdre_Verdict {
100	    rbtdre_Verdict::Pass
101	}
102	
103	fn rbtdrl_failfast_fail(_dir: &Path) -> rbtdre_Verdict {
104	    rbtdre_Verdict::Fail("calibrant intra-section fail trigger".to_string())
105	}
106	
107	/// Section-A trailing case. Under default fail-fast it never runs and its
108	/// sentinel must be absent; under keep-going it runs and writes the sentinel.
109	fn rbtdrl_failfast_not_reached_intra(dir: &Path) -> rbtdre_Verdict {
110	    if let Err(v) = rbtdrl_write_sentinel(dir) {
111	        return v;
112	    }
113	    rbtdre_Verdict::Pass
114	}
115	
116	/// Section-B sole case. Under default fail-fast no §B case runs; under
117	/// keep-going it runs and writes the sentinel. Distinguishes inter-section
118	/// fail-fast from the intra-section variant.
119	fn rbtdrl_failfast_not_reached_inter(dir: &Path) -> rbtdre_Verdict {
120	    if let Err(v) = rbtdrl_write_sentinel(dir) {
121	        return v;
122	    }
123	    rbtdre_Verdict::Pass
124	}
125	
126	pub static RBTDRL_SECTIONS_FAIL_FAST: &[rbtdre_Section] = &[
127	    rbtdre_Section {
128	        name: "fail-fast-intra-section",
129	        cases: &[
130	            case!(rbtdrl_failfast_pass),
131	            case!(rbtdrl_failfast_fail),
132	            case!(rbtdrl_failfast_not_reached_intra),
133	        ],
134	    },
135	    rbtdre_Section {
136	        name: "fail-fast-inter-section",
137	        cases: &[case!(rbtdrl_failfast_not_reached_inter)],
138	    },
139	];
140	
141	// ── calibrant-progressing ───────────────────────────────────
142	
143	/// Probe-Ok mechanism: deterministic Ok return. No env-var or file coupling
144	/// — a single fixture run exercises the case-body-runs-after-Probe-Ok path.
145	fn rbtdrl_probe_ok() -> Result<(), String> {
146	    Ok(())
147	}
148	
149	/// Probe-Err mechanism: deterministic Err return. Case body never runs, so a
150	/// single fixture run exercises the Fail-via-Probe-Err path. Required by the
151	/// blackbox driver to verify rbtdrb_assert's "precondition '%s' not met:" +
152	/// "remediation:" stderr format.
153	fn rbtdrl_probe_err() -> Result<(), String> {
154	    Err("calibrant deterministic probe failure".to_string())
155	}
156	
157	fn rbtdrl_progressing_probe_ok(_dir: &Path) -> rbtdre_Verdict {
158	    let probe = rbtdrb_Probe {
159	        name: "calibrant deterministic ok",
160	        check: rbtdrl_probe_ok,
161	        remediation: "n/a — deterministic probe always Ok",
162	    };
163	    if let Err(v) = rbtdrb_assert(&probe) {
164	        return v;
165	    }
166	    rbtdre_Verdict::Pass
167	}
168	
169	fn rbtdrl_progressing_probe_err(_dir: &Path) -> rbtdre_Verdict {
170	    let probe = rbtdrb_Probe {
171	        name: "calibrant deterministic err",
172	        check: rbtdrl_probe_err,
173	        remediation: "n/a — deterministic probe always Err for engine surface verification",
174	    };
175	    if let Err(v) = rbtdrb_assert(&probe) {
176	        return v;
177	    }
178	    rbtdre_Verdict::Fail("calibrant probe-err case body executed unexpectedly".to_string())
179	}
180	
181	pub static RBTDRL_SECTIONS_PROGRESSING: &[rbtdre_Section] = &[rbtdre_Section {
182	    name: "calibrant-progressing",
183	    cases: &[
184	        case!(rbtdrl_progressing_probe_ok),
185	        case!(rbtdrl_progressing_probe_err),
186	    ],
187	}];
188	
189	// ── calibrant-sentinel ──────────────────────────────────────
190	
191	/// Single-case Independent fixture used as a suite-level fail-fast pivot:
192	/// place this fixture after a failing fixture in the calibrant suite and
193	/// assert the sentinel is absent.
194	fn rbtdrl_sentinel_marks(dir: &Path) -> rbtdre_Verdict {
195	    if let Err(v) = rbtdrl_write_sentinel(dir) {
196	        return v;
197	    }
198	    rbtdre_Verdict::Pass
199	}
200	
201	pub static RBTDRL_SECTIONS_SENTINEL: &[rbtdre_Section] = &[rbtdre_Section {
202	    name: "calibrant-sentinel",
203	    cases: &[case!(rbtdrl_sentinel_marks)],
204	}];
205	
206	// ── Fixture statics ──────────────────────────────────────────
207	
208	pub static RBTDRL_FIXTURE_VERDICTS: rbtdre_Fixture = rbtdre_Fixture {
209	    name: RBTDRM_FIXTURE_CALIBRANT_VERDICTS,
210	    disposition: rbtdre_Disposition::Independent,
211	    setup: None,
212	    teardown: None,
213	    sections: RBTDRL_SECTIONS_VERDICTS,
214	};
215	
216	pub static RBTDRL_FIXTURE_FAIL_FAST: rbtdre_Fixture = rbtdre_Fixture {
217	    name: RBTDRM_FIXTURE_CALIBRANT_FAIL_FAST,
218	    disposition: rbtdre_Disposition::Independent,
219	    setup: None,
220	    teardown: None,
221	    sections: RBTDRL_SECTIONS_FAIL_FAST,
222	};
223	
224	pub static RBTDRL_FIXTURE_PROGRESSING: rbtdre_Fixture = rbtdre_Fixture {
225	    name: RBTDRM_FIXTURE_CALIBRANT_PROGRESSING,
226	    disposition: rbtdre_Disposition::StateProgressing,
227	    setup: None,
228	    teardown: None,
229	    sections: RBTDRL_SECTIONS_PROGRESSING,
230	};
231	
232	pub static RBTDRL_FIXTURE_SENTINEL: rbtdre_Fixture = rbtdre_Fixture {
233	    name: RBTDRM_FIXTURE_CALIBRANT_SENTINEL,
234	    disposition: rbtdre_Disposition::Independent,
235	    setup: None,
236	    teardown: None,
237	    sections: RBTDRL_SECTIONS_SENTINEL,
238	};
