240	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
241	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
242	    let required = match rbtdrm_required_colophons(fixture) {
243	        Some(r) => r,
244	        None => {
245	            return Err(format!(
246	                "rbtd: unknown fixture '{}' — not registered in manifest",
247	                fixture
248	            ));
249	        }
250	    };
251	    for colophon in required {
252	        let found = manifest.split_whitespace().any(|token| token == *colophon);
253	        if !found {
254	            return Err(format!(
255	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
256	                colophon, fixture
257	            ));
258	        }
259	    }
260	    Ok(())
261	}
