106	/// Case registration macro. Derives case name from function name via `stringify!`.
107	/// Compiler enforces uniqueness — duplicate function names won't compile.
108	#[macro_export]
109	macro_rules! case {
110	    ($func:path) => {
111	        $crate::rbtdre_engine::rbtdre_Case {
112	            name: stringify!($func),
113	            func: $func,
114	        }
115	    };
116	}
