125	    pub white: &'static str,
126	    pub reset: &'static str,
127	}
128	
129	/// Detect terminal color support from TERM environment variable.
130	pub fn rbtdre_detect_colors() -> rbtdre_Colors {
131	    match std::env::var("TERM") {
132	        Ok(term) if !term.is_empty() && term != "dumb" => rbtdre_Colors {
133	            green: "\x1b[1;32m",
134	            red: "\x1b[1;31m",
135	            yellow: "\x1b[1;33m",
136	            white: "\x1b[1;37m",
137	            reset: "\x1b[0m",
138	        },
139	        _ => rbtdre_Colors {
140	            green: "",
141	            red: "",
142	            yellow: "",
143	            white: "",
144	            reset: "",
145	        },
146	    }
147	}
