149	// ── Trace ──────────────────────────────────────────────────────
150	
151	/// Write verdict and detail to a trace file in the case temp directory.
152	fn rbtdre_write_trace(case_dir: &Path, display_name: &str, verdict: &rbtdre_Verdict) {
153	    let content = match verdict {
154	        rbtdre_Verdict::Pass => format!("PASSED: {}\n", display_name),
155	        rbtdre_Verdict::Fail(detail) => format!("FAILED: {}\n\n{}\n", display_name, detail),
156	        rbtdre_Verdict::Skip(reason) => {
157	            format!("SKIPPED: {}\n\nReason: {}\n", display_name, reason)
158	        }
159	    };
160	    let _ = std::fs::write(case_dir.join("trace.txt"), content);
161	}
162	
163	// ── Dispatch ───────────────────────────────────────────────────
164	
165	/// Aggregate results from running sections.
166	pub struct rbtdre_RunResult {
167	    pub passed: usize,
168	    pub failed: usize,
169	    pub skipped: usize,
170	    pub temp_dir: PathBuf,
171	}
172	
173	/// Run all sections sequentially, dispatching each case with per-case temp dir isolation.
174	pub fn rbtdre_run_sections(
175	    sections: &[rbtdre_Section],
176	    colors: &rbtdre_Colors,
177	    fail_fast: bool,
178	    root_temp: &Path,
179	) -> Result<rbtdre_RunResult, String> {
180	    let mut passed = 0usize;
181	    let mut failed = 0usize;
182	    let mut skipped = 0usize;
183	
184	    'outer: for section in sections {
185	        eprintln!(
186	            "\n{}--- {} ---{}",
187	            colors.white, section.name, colors.reset
188	        );
189	
190	        for case in section.cases {
191	            let case_dir = root_temp.join(case.name);
192	            std::fs::create_dir_all(&case_dir).map_err(|e| {
193	                format!("rbtd: failed to create case dir '{}': {}", case.name, e)
194	            })?;
195	
196	            let verdict = (case.func)(&case_dir);
197	            rbtdre_write_trace(&case_dir, case.name, &verdict);
198	
199	            match &verdict {
200	                rbtdre_Verdict::Pass => {
201	                    eprintln!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
202	                    passed += 1;
203	                }
204	                rbtdre_Verdict::Fail(_) => {
205	                    eprintln!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
206	                    failed += 1;
207	                    if fail_fast {
208	                        break 'outer;
209	                    }
210	                }
211	                rbtdre_Verdict::Skip(_) => {
212	                    eprintln!(
213	                        "{}SKIPPED:{} {}",
214	                        colors.yellow, colors.reset, case.name
215	                    );
216	                    skipped += 1;
217	                }
218	            }
219	        }
220	    }
221	
222	    Ok(rbtdre_RunResult {
223	        passed,
224	        failed,
225	        skipped,
226	        temp_dir: root_temp.to_path_buf(),
227	    })
228	}
229	
230	/// Print colored summary line and trace directory location.
231	pub fn rbtdre_print_summary(result: &rbtdre_RunResult, colors: &rbtdre_Colors) {
232	    let total = result.passed + result.failed + result.skipped;
233	    let (color, end_color) = if result.failed > 0 {
234	        (colors.red, colors.reset)
235	    } else {
236	        (colors.green, colors.reset)
237	    };
238	
239	    eprintln!(
240	        "\n{}{} passed, {} failed, {} skipped ({} total){}",
241	        color, result.passed, result.failed, result.skipped, total, end_color,
242	    );
243	    eprintln!("Trace dir: {}", result.temp_dir.display());
244	}
