246	// ── Single-case operations ───────────────────────────────────
247	
248	/// Find a case by name within sections.
249	pub fn rbtdre_find_case<'a>(
250	    sections: &'a [rbtdre_Section],
251	    target: &str,
252	) -> Option<&'a rbtdre_Case> {
253	    for section in sections {
254	        for case in section.cases {
255	            if case.name == target {
256	                return Some(case);
257	            }
258	        }
259	    }
260	    None
261	}
262	
263	/// List all cases grouped by section.
264	pub fn rbtdre_list_cases(sections: &[rbtdre_Section]) {
265	    for section in sections {
266	        eprintln!("\n--- {} ---", section.name);
267	        for case in section.cases {
268	            eprintln!("  {}", case.name);
269	        }
270	    }
271	}
272	
273	/// Run a fixture: setup hook → cases → teardown hook (finally-shaped).
274	///
275	/// Expects the invocation context to already be installed in the thread-local
276	/// (via `rbtdrc_set_context`); setup/teardown access ctx via that channel.
277	///
278	/// Setup failure short-circuits cases but still invokes teardown. Teardown
279	/// errors are surfaced as warnings via stderr; the function never panics on
280	/// teardown failure.
281	pub fn rbtdre_run_fixture(
282	    fixture: &'static rbtdre_Fixture,
283	    colors: &rbtdre_Colors,
284	    root_temp: &Path,
285	) -> Result<rbtdre_RunResult, String> {
286	    let setup_result = match fixture.setup {
287	        Some(f) => f(),
288	        None => Ok(()),
289	    };
290	
291	    let run_result = match setup_result {
292	        Ok(()) => {
293	            let fail_fast = rbtdre_resolve_fail_fast(fixture.disposition, false)
294	                .expect("disposition-default mode never fails policy resolution");
295	            rbtdre_run_sections(fixture.sections, colors, fail_fast, root_temp)
296	        }
297	        Err(msg) => Err(format!("rbtd: fixture '{}' setup failed: {}", fixture.name, msg)),
298	    };
299	
300	    if let Some(f) = fixture.teardown {
301	        f();
302	    }
303	
304	    run_result
305	}
306	
307	/// Run a single case without charge/quench lifecycle.
308	pub fn rbtdre_run_single_case(
309	    case: &rbtdre_Case,
310	    colors: &rbtdre_Colors,
311	    root_temp: &Path,
312	) -> Result<rbtdre_RunResult, String> {
313	    let case_dir = root_temp.join(case.name);
314	    std::fs::create_dir_all(&case_dir)
315	        .map_err(|e| format!("rbtd: failed to create case dir '{}': {}", case.name, e))?;
316	
317	    let verdict = (case.func)(&case_dir);
318	    rbtdre_write_trace(&case_dir, case.name, &verdict);
319	
320	    let (passed, failed, skipped) = match &verdict {
321	        rbtdre_Verdict::Pass => {
322	            eprintln!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
323	            (1, 0, 0)
324	        }
325	        rbtdre_Verdict::Fail(_) => {
326	            eprintln!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
327	            (0, 1, 0)
328	        }
329	        rbtdre_Verdict::Skip(_) => {
330	            eprintln!("{}SKIPPED:{} {}", colors.yellow, colors.reset, case.name);
331	            (0, 0, 1)
332	        }
333	    };
334	
335	    Ok(rbtdre_RunResult {
336	        passed,
337	        failed,
338	        skipped,
339	        temp_dir: root_temp.to_path_buf(),
340	    })
341	}
