17	// RBTD Theurge — test orchestrator entry point
18	//
19	// Subcommands:
20	//   rbtd <manifest> <fixture>
21	//     Suite runner — verify manifest, charge, run all cases, quench.
22	//   rbtd single <manifest> <fixture> [case]
23	//     Single-case runner — no charge/quench. List cases or run one.
24	
25	use std::process::ExitCode;
26	
27	use rbtd::rbtdrc_crucible::{
28	    rbtdrc_lookup_fixture, rbtdrc_set_context, rbtdrc_take_context,
29	};
30	use rbtd::rbtdre_engine::{
31	    rbtdre_detect_colors, rbtdre_find_case, rbtdre_list_cases, rbtdre_print_summary,
32	    rbtdre_run_fixture, rbtdre_run_single_case,
33	};
34	use rbtd::rbtdri_invocation::{rbtdri_Context, rbtdri_invoke_global};
35	use rbtd::rbtdrm_manifest::{rbtdrm_verify, RBTDRM_COLOPHON_CRUCIBLE_ACTIVE};
36	
37	fn main() -> ExitCode {
38	    let args: Vec<String> = std::env::args().collect();
39	
40	    if args.get(1).map(|s| s.as_str()) == Some("single") {
41	        return run_single(&args[2..]);
42	    }
43	
44	    run_suite(&args[1..])
45	}
46	
47	// ── Suite runner ─────────────────────────────────────────────
48	
49	fn run_suite(args: &[String]) -> ExitCode {
50	    let manifest = match args.first() {
51	        Some(m) => m,
52	        None => {
53	            eprintln!(
54	                "rbtd: usage: rbtd <manifest> <fixture>\n\
55	                 theurge must be launched via tabtarget (e.g. tt/rbtd-r.FixtureRun.tadmor.sh)"
56	            );
57	            return ExitCode::FAILURE;
58	        }
59	    };
60	
61	    let fixture = match args.get(1) {
62	        Some(n) => n,
63	        None => {
64	            eprintln!("rbtd: no fixture argument — which test fixture to run?");
65	            return ExitCode::FAILURE;
66	        }
67	    };
68	
69	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
70	        eprintln!("{}", msg);
71	        return ExitCode::FAILURE;
72	    }
73	
74	    let project_root = match std::env::current_dir() {
75	        Ok(p) => p,
76	        Err(e) => {
77	            eprintln!("rbtd: cannot determine working directory: {}", e);
78	            return ExitCode::FAILURE;
79	        }
80	    };
81	
82	    let root_temp = std::env::temp_dir().join(format!("rbtd-{}", std::process::id()));
83	    if let Err(e) = std::fs::create_dir_all(&root_temp) {
84	        eprintln!("rbtd: failed to create temp dir: {}", e);
85	        return ExitCode::FAILURE;
86	    }
87	
88	    let burv_root = root_temp.join("burv");
89	    let ctx = rbtdri_Context::new(&project_root, fixture, &burv_root);
90	
91	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
92	        Some(f) => f,
93	        None => {
94	            eprintln!(
95	                "rbtd: fixture '{}' has no registered Fixture — \
96	                 manifest verification accepted the name but no Fixture static is bound. \
97	                 Update rbtdrc_lookup_fixture in rbtdrc_crucible.rs.",
98	                fixture
99	            );
100	            return ExitCode::FAILURE;
101	        }
102	    };
103	
104	    rbtdrc_set_context(ctx);
105	
106	    let colors = rbtdre_detect_colors();
107	    let run_result = rbtdre_run_fixture(fixture_def, &colors, &root_temp);
108	
109	    let _ctx = rbtdrc_take_context();
110	
111	    let result = match run_result {
112	        Ok(r) => r,
113	        Err(msg) => {
114	            eprintln!("rbtd: {}", msg);
115	            return ExitCode::FAILURE;
116	        }
117	    };
118	
119	    rbtdre_print_summary(&result, &colors);
120	
121	    if result.failed > 0 {
122	        eprintln!("rbtd: {} case(s) failed", result.failed);
123	        ExitCode::FAILURE
124	    } else {
125	        ExitCode::SUCCESS
126	    }
127	}
128	
129	// ── Single-case runner ───────────────────────────────────────
130	
131	fn run_single(args: &[String]) -> ExitCode {
132	    let manifest = match args.first() {
133	        Some(m) => m,
134	        None => {
135	            eprintln!(
136	                "rbtd single: usage: rbtd single <manifest> <fixture> [case]\n\
137	                 omit case to list all cases for the fixture"
138	            );
139	            return ExitCode::FAILURE;
140	        }
141	    };
142	
143	    let fixture = match args.get(1) {
144	        Some(f) => f,
145	        None => {
146	            eprintln!("rbtd single: no fixture argument");
147	            return ExitCode::FAILURE;
148	        }
149	    };
150	
151	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
152	        eprintln!("{}", msg);
153	        return ExitCode::FAILURE;
154	    }
155	
156	    // Set up execution context early — needed for charge check and case execution
157	    let project_root = match std::env::current_dir() {
158	        Ok(p) => p,
159	        Err(e) => {
160	            eprintln!("rbtd: cannot determine working directory: {}", e);
161	            return ExitCode::FAILURE;
162	        }
163	    };
164	
165	    let root_temp = std::env::temp_dir().join(format!("rbtd-{}", std::process::id()));
166	    if let Err(e) = std::fs::create_dir_all(&root_temp) {
167	        eprintln!("rbtd: failed to create temp dir: {}", e);
168	        return ExitCode::FAILURE;
169	    }
170	
171	    // Context is required for every case execution path (rbtdrc_with_ctx).
172	    // Fixtures with a setup hook (crucible charge) additionally verify their
173	    // crucible is charged externally — single-case mode never charges.
174	    let burv_root = root_temp.join("burv");
175	    let mut ctx = rbtdri_Context::new(&project_root, fixture, &burv_root);
176	
177	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
178	        Some(f) => f,
179	        None => {
180	            eprintln!(
181	                "rbtd single: fixture '{}' has no registered Fixture",
182	                fixture
183	            );
184	            return ExitCode::FAILURE;
185	        }
186	    };
187	
188	    if fixture_def.setup.is_some() {
189	        match rbtdri_invoke_global(
190	            &mut ctx,
191	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
192	            &[fixture],
193	            &[],
194	        ) {
195	            Ok(r) if r.exit_code == 0 => {}
196	            _ => {
197	                eprintln!(
198	                    "rbtd single: crucible not charged for '{}'\n\
199	                     charge first: tt/rbw-cC.Charge.{}.sh",
200	                    fixture, fixture
201	                );
202	                return ExitCode::FAILURE;
203	            }
204	        }
205	    }
206	
207	    rbtdrc_set_context(ctx);
208	
209	    let sections = fixture_def.sections;
210	
211	    // No case argument — list all cases
212	    let case_name = match args.get(2) {
213	        None => {
214	            rbtdre_list_cases(sections);
215	            return ExitCode::SUCCESS;
216	        }
217	        Some(n) => n,
218	    };
219	
220	    // Find the case
221	    let case = match rbtdre_find_case(sections, case_name) {
222	        Some(c) => c,
223	        None => {
224	            eprintln!(
225	                "rbtd single: case '{}' not found in fixture '{}'",
226	                case_name, fixture
227	            );
228	            rbtdre_list_cases(sections);
229	            return ExitCode::FAILURE;
230	        }
231	    };
232	
233	    let colors = rbtdre_detect_colors();
234	    let result = match rbtdre_run_single_case(case, &colors, &root_temp) {
235	        Ok(r) => r,
236	        Err(msg) => {
237	            eprintln!("rbtd: case execution error: {}", msg);
238	            return ExitCode::FAILURE;
239	        }
240	    };
241	
242	    rbtdre_print_summary(&result, &colors);
243	
244	    if result.failed > 0 {
245	        ExitCode::FAILURE
246	    } else {
247	        ExitCode::SUCCESS
248	    }
249	}
