40	    RBTDRM_COLOPHON_FIAT, RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE, RBTDRM_COLOPHON_ORDAIN,
41	    RBTDRM_COLOPHON_QUENCH, RBTDRM_COLOPHON_REKON_HALLMARK, RBTDRM_COLOPHON_TALLY,
