45	// ── Thread-local invocation context ──────────────────────────
46	
47	/// Ifrit binary name inside the bottle container.
48	const RBTDRC_IFRIT_BINARY: &str = "rbid";
49	
50	/// Test connectivity target — ICANN-owned, stable single /20 CIDR (192.0.32.0/20)
51	const RBTDRC_CONNECTIVITY_DOMAIN: &str = "www.internic.net";
52	
53	thread_local! {
54	    static RBTDRC_CTX: RefCell<Option<rbtdri_Context>> = RefCell::new(None);
55	}
56	
57	/// Store invocation context for case functions. Called before run_sections.
58	pub fn rbtdrc_set_context(ctx: rbtdri_Context) {
59	    RBTDRC_CTX.with(|c| *c.borrow_mut() = Some(ctx));
60	}
61	
62	/// Retrieve invocation context after cases complete. Called for quench.
63	pub fn rbtdrc_take_context() -> rbtdri_Context {
64	    RBTDRC_CTX.with(|c| {
65	        c.borrow_mut()
66	            .take()
67	            .expect("rbtdrc: no context — was rbtdrc_set_context called?")
68	    })
69	}
70	
71	pub(crate) fn rbtdrc_with_ctx<F>(f: F) -> rbtdre_Verdict
72	where
73	    F: FnOnce(&mut rbtdri_Context) -> rbtdre_Verdict,
74	{
75	    RBTDRC_CTX.with(|c| {
76	        let mut opt = c.borrow_mut();
77	        let ctx = opt
78	            .as_mut()
79	            .expect("rbtdrc: no invocation context for case execution");
80	        f(ctx)
81	    })
82	}
83	
84	// ── Crucible lifecycle hooks (setup/teardown) ────────────────
85	
86	/// Setup hook for crucible fixtures: charge → CrucibleActive assertion →
87	/// readiness delay (for service-bearing nameplates). Reads ctx from thread-
88	/// local. Returns Err on any step failure; engine surfaces this as a fixture
89	/// failure and runs teardown anyway.
90	///
91	/// Readiness-delay handling currently consults a hardcoded service-fixture
92	/// set; pace ₢BBAAt migrates the delay to a per-nameplate fact
93	/// (`RBRN_BOTTLE_READINESS_DELAY_SEC`) read by the charge tabtarget itself,
94	/// at which point this function loses the wait entirely.
95	pub fn rbtdrc_charge_crucible() -> Result<(), String> {
96	    RBTDRC_CTX.with(|c| {
97	        let mut opt = c.borrow_mut();
98	        let ctx = opt
99	            .as_mut()
100	            .ok_or_else(|| "rbtdrc: no invocation context for charge".to_string())?;
101	        zrbtdrc_charge_impl(ctx)
102	    })
103	}
104	
105	/// Teardown hook for crucible fixtures: quench → inverse CrucibleActive
106	/// assertion. Reads ctx from thread-local. Best-effort — surfaces failures as
107	/// stderr warnings rather than errors; teardown always completes.
108	pub fn rbtdrc_quench_crucible() {
109	    RBTDRC_CTX.with(|c| {
110	        let mut opt = c.borrow_mut();
111	        if let Some(ctx) = opt.as_mut() {
112	            zrbtdrc_quench_impl(ctx);
113	        } else {
114	            eprintln!("Warning: rbtdrc: no invocation context for quench — skipped");
115	        }
116	    });
117	}
118	
119	fn zrbtdrc_charge_impl(ctx: &mut rbtdri_Context) -> Result<(), String> {
120	    let fixture = ctx.fixture().to_string();
121	    eprintln!("\nCharging crucible for nameplate '{}'...", fixture);
122	    match rbtdri_invoke(ctx, RBTDRM_COLOPHON_CHARGE, &[]) {
123	        Ok(r) if r.exit_code == 0 => {
124	            eprintln!("Crucible charged");
125	        }
126	        Ok(r) => {
127	            return Err(format!("Charge failed (exit {})\n{}", r.exit_code, r.stderr));
128	        }
129	        Err(e) => {
130	            return Err(format!("Charge invocation failed: {}", e));
131	        }
132	    }
133	
134	    eprintln!("Verifying crucible is active after charge...");
135	    match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_CRUCIBLE_ACTIVE, &[&fixture], &[]) {
136	        Ok(r) if r.exit_code == 0 => {
137	            eprintln!("Crucible active confirmed");
138	        }
139	        Ok(r) => {
140	            return Err(format!(
141	                "Lifecycle assertion failed: crucible not active after charge (exit {})\n{}",
142	                r.exit_code, r.stderr
143	            ));
144	        }
145	        Err(e) => {
146	            return Err(format!(
147	                "CrucibleActive invocation failed after charge: {}",
148	                e
149	            ));
150	        }
151	    }
152	
153	    if zrbtdrc_needs_readiness_delay(&fixture) {
154	        eprintln!(
155	            "Waiting {}s for service readiness...",
156	            RBTDRC_SERVICE_READINESS_DELAY_SECS
157	        );
158	        std::thread::sleep(std::time::Duration::from_secs(
159	            RBTDRC_SERVICE_READINESS_DELAY_SECS,
160	        ));
161	    }
162	
163	    Ok(())
164	}
