170	        Ok(r) if r.exit_code == 0 => eprintln!("Crucible quenched"),
171	        Ok(r) => eprintln!("Warning: quench exited {}", r.exit_code),
172	        Err(e) => eprintln!("Warning: quench invocation failed: {}", e),
173	    }
174	
175	    eprintln!("Verifying crucible is inactive after quench...");
176	    match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_CRUCIBLE_ACTIVE, &[&fixture], &[]) {
177	        Ok(r) if r.exit_code != 0 => {
178	            eprintln!("Crucible inactive confirmed");
179	        }
180	        Ok(r) => {
181	            eprintln!(
182	                "Warning: crucible still active after quench (exit {})",
183	                r.exit_code
184	            );
185	        }
186	        Err(e) => {
187	            eprintln!(
188	                "Warning: CrucibleActive invocation failed after quench: {}",
189	                e
190	            );
191	        }
192	    }
